#include <iostream>
#include <string>
using namespace std;

class Student {
public:
    // Data members
    string name;
    int rollNo;
    float marks;

    // Default Constructor
    Student() {
        name = "Unknown";
        rollNo = 0;
        marks = 0.0;
        cout << "Default Constructor Called" << endl;
    }

    // Parameterized Constructor
    Student(string n, int r, float m) {
        name = n;
        rollNo = r;
        marks = m;
        cout << "Parameterized Constructor Called" << endl;
    }

    // Member function to display student info
    void display() {
        cout << "Name: " << name << endl;
        cout << "Roll No: " << rollNo << endl;
        cout << "Marks: " << marks << endl;
    }

    // Destructor
    ~Student() {
        cout << "Destructor called for " << name << endl;
    }
};

int main() {
    // Creating objects
    Student s1;  // Calls default constructor
    s1.display();

    cout << "---" << endl;

    Student s2("Amit Kumar", 101, 85.5);  // Calls parameterized constructor
    s2.display();

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

class BankAccount {
private:
    // Private data members - hidden from outside
    string accountHolder;
    string accountNumber;
    double balance;
    const double minimumBalance = 500.0;  // Constant member

public:
    // Public constructor
    BankAccount(string holder, string accNo, double initialBalance) {
        accountHolder = holder;
        accountNumber = accNo;
        // Validate initial balance
        if (initialBalance >= minimumBalance) {
            balance = initialBalance;
        } else {
            balance = minimumBalance;
            cout << "Initial balance too low. Set to minimum." << endl;
        }
    }

    // Getter methods (accessors) - read-only access
    string getHolderName() const {
        return accountHolder;
    }

    string getAccountNumber() const {
        return accountNumber;
    }

    double getBalance() const {
        return balance;
    }

    // Setter methods (mutators) - controlled modification
    void setHolderName(string name) {
        if (!name.empty()) {
            accountHolder = name;
        }
    }

    // Member function to deposit money
    void deposit(double amount) {
        if (amount > 0) {
            balance += amount;
            cout << "Deposited: " << amount << endl;
        } else {
            cout << "Invalid deposit amount" << endl;
        }
    }

    // Member function to withdraw money
    bool withdraw(double amount) {
        if (amount > 0 && (balance - amount) >= minimumBalance) {
            balance -= amount;
            cout << "Withdrawn: " << amount << endl;
            return true;
        } else {
            cout << "Insufficient balance or invalid amount" << endl;
            return false;
        }
    }

    // Display account info
    void display() const {
        cout << "Account Holder: " << accountHolder << endl;
        cout << "Account Number: " << accountNumber << endl;
        cout << "Balance: " << balance << endl;
    }
};

int main() {
    // Create BankAccount object
    BankAccount acc("Rahul Sharma", "ACCT123456", 5000);

    cout << "=== Initial Account ===" << endl;
    acc.display();

    cout << "\n=== Transactions ===" << endl;
    acc.deposit(1000);
    acc.withdraw(2000);

    cout << "\n=== Final Account ===" << endl;
    acc.display();

    // Using getter
    cout << "\nBalance via getter: " << acc.getBalance() << endl;

    return 0;
}

#include <iostream>
#include <string>
using namespace std;

// Base class (Parent class)
class Person {
protected:  // Protected: accessible in derived classes, hidden from outside
    string name;
    int age;

public:
    Person(string n, int a) : name(n), age(a) {
        cout << "Person Constructor: " << name << endl;
    }

    virtual void display() const {
        cout << "Name: " << name << ", Age: " << age << endl;
    }

    // Virtual function for polymorphism
    virtual void work() const {
        cout << name << " is doing some work." << endl;
    }

    // Pure virtual function - makes Person abstract
    virtual void introduce() const = 0;

    virtual ~Person() {
        cout << "Person Destructor: " << name << endl;
    }
};

// Derived class (Child class) - Single Inheritance
class Student : public Person {
private:
    string studentId;
    float gpa;

public:
    Student(string n, int a, string id, float g) 
        : Person(n, a), studentId(id), gpa(g) {
        cout << "Student Constructor: " << name << endl;
    }

    // Overriding base class method
    void display() const override {
        cout << "[Student] Name: " << name << ", Age: " << age 
             << ", ID: " << studentId << ", GPA: " << gpa << endl;
    }

    // Override work() method
    void work() const override {
        cout << name << " is studying and completing assignments." << endl;
    }

    void introduce() const override {
        cout << "Hi, I'm " << name << ", a student with GPA " << gpa << endl;
    }

    ~Student() {
        cout << "Student Destructor: " << name << endl;
    }
};

// Another derived class
class Teacher : public Person {
private:
    string subject;
    double salary;

public:
    Teacher(string n, int a, string sub, double sal) 
        : Person(n, a), subject(sub), salary(sal) {
        cout << "Teacher Constructor: " << name << endl;
    }

    void display() const override {
        cout << "[Teacher] Name: " << name << ", Age: " << age 
             << ", Subject: " << subject << ", Salary: " << salary << endl;
    }

    void work() const override {
        cout << name << " is teaching " << subject << endl;
    }

    void introduce() const override {
        cout << "Hello, I'm " << name << ", I teach " << subject << endl;
    }

    ~Teacher() {
        cout << "Teacher Destructor: " << name << endl;
    }
};

// Function demonstrating polymorphism
void demonstrateWork(Person* p) {
    p->work();  // Runtime polymorphism - calls appropriate derived method
}

int main() {
    cout << "=== Creating Objects ===" << endl;
    Student s("Priya", 20, "STU001", 8.5);
    Teacher t("Dr. Sharma", 45, "Data Structures", 75000);

    cout << "\n=== Using Base Class Pointer (Polymorphism) ===" << endl;
    Person* ptr1 = &s;
    Person* ptr2 = &t;

    // Virtual function calls - runtime polymorphism
    ptr1->display();
    ptr2->display();

    cout << "\n=== Polymorphic Function Call ===" << endl;
    demonstrateWork(ptr1);
    demonstrateWork(ptr2);

    cout << "\n=== Pure Virtual Function (Abstract Method) ===" << endl;
    s.introduce();
    t.introduce();

    cout << "\n=== Destructors Called ===" << endl;
    return 0;
}
